// calcPage.cy.ts
import calcCreated from '../fixtures/interestApi/interestCalcCreated.json';
import campaignBanner from '../fixtures/sanity/campaignBanner.json';

interface CalcData {
  id: string;
  status: string;
  products: any[];
  is_otovo_campaign?: boolean;
}

const TEST_CONSTANTS = {
  PHONE: '+4797152222',
  EMAIL: 'ole@brumm.io',
  NAME: 'Ole Brumm',
  BASE_URL: 'http://localhost:3000',
  TIMEOUTS: {
    DEFAULT: 10000,
    NETWORK: 5000,
  },
};

describe('Calculation page', () => {
  beforeEach(() => {
    // Common intercepts
    cy.intercept('GET', '**/web/customforms/**', {}).as('customForms');
    cy.intercept('POST', '**/web/campaigns/generate-referral-code/', {
      url: 'https://foo.bar',
    }).as('referralCode');
    cy.intercept('GET', '**campaignBanner**', campaignBanner).as('campaignBanner');

    // Store calculation data for reuse
    cy.wrap(calcCreated).as('calcData');
  });

  const setupCalcPageIntercepts = (calc: CalcData) => {
    cy.intercept(
      'GET',
      `**/web/interests/${calc.id}/`,
      calc
    ).as('interestDetailApiCall');

    cy.intercept(
      'GET',
      `**/web/interests/${calc.id}/products/`,
      calc.products
    ).as('productsApiCall');
  };

  const visitCalcPage = (calcId: string) => {
    cy.visit(`${TEST_CONSTANTS.BASE_URL}/es-es/solar/redirect/${calcId}`);
    cy.url().should('include', 'products');
  };

  it('should show the otovo campaign', () => {
    const calcCreatedWithOtovoCampaign: CalcData = {
      ...calcCreated,
      is_otovo_campaign: true,
    };

    setupCalcPageIntercepts(calcCreatedWithOtovoCampaign);
    visitCalcPage(calcCreatedWithOtovoCampaign.id);

    cy.get('[data-testid="campaign-banner-otovo_campaign"]', {
      timeout: TEST_CONSTANTS.TIMEOUTS.DEFAULT,
    }).should('be.visible');
  });

  it('should activate calculation', () => {
    setupCalcPageIntercepts(calcCreated);
    visitCalcPage(calcCreated.id);

    // Verify initial page state
    cy.get('[data-testid="purchase-model-selector-LEASING"]').should('be.visible');
    cy.get('[data-testid="campaign-banner-global"]').should('be.visible');
    cy.get('[data-testid="purchase-model-selector-NOW"]').should('be.visible');
    cy.get('[data-testid="contact-form"]').should('not.exist');

    // Verify API calls
    cy.wait('@interestDetailApiCall');
    cy.wait('@productsApiCall');
    cy.get('@interestDetailApiCall.all').should('have.length.of.at.least', 1);
    cy.get('@productsApiCall.all').should('have.length', 1);

    // Setup activation intercept
    cy.intercept('POST', `**/web/interests/${calcCreated.id}/activate/`, {
      statusCode: 204,
    }).as('activateRequest');

    // Activate calculation
    cy.get('[data-testid="accept-calculation-button"]')
      .should('be.visible')
      .click();

    cy.wait('@activateRequest')
      .its('response.statusCode')
      .should('eq', 204);

    // Verify contact form appears
    cy.get('[data-testid="contact-form"]', {
      timeout: TEST_CONSTANTS.TIMEOUTS.DEFAULT,
    })
      .should('be.visible')
      .within(() => {
        // Phone number validation
        cy.intercept('POST', '/web/user_validation/validate_phone_number/', {
          statusCode: 400,
          body: { foo: 'bar' },
        }).as('invalidPhoneValidation');

        cy.get('[data-testid="contact-phone-number"]').type('+4797');
        cy.get('[data-testid="contact-email"]').type(TEST_CONSTANTS.EMAIL);
        cy.get('[data-testid="contact-name"]').type(TEST_CONSTANTS.NAME);

        cy.contains('Número de teléfono no válido').should('be.visible');
        cy.get('[data-testid="submit-contact-me-form"]').click();

        // Setup valid phone validation
        cy.intercept('POST', '/web/user_validation/validate_phone_number/', {
          formatted: '+47 97 15 22 22',
          country_code: 47,
        }).as('validPhoneValidation');

        cy.get('[data-testid="contact-phone-number"]').type('152222');
      });

    // Setup submission intercepts
    const calcAccepted = {
      ...calcCreated,
      status: 'calc_accepted',
    };

    cy.intercept(
      'GET',
      `**/web/interests/${calcAccepted.id}/`,
      calcAccepted
    ).as('acceptedCalc');

    cy.intercept(
      'POST',
      `**/web/interests/${calcAccepted.id}/user_form_interaction/`,
      {}
    ).as('formInteraction');

    cy.intercept(
      'POST',
      `**/web/interests/${calcAccepted.id}/user_form_question_interaction/`,
      {}
    ).as('questionInteraction');

    // Submit form
    cy.get('[data-testid="submit-contact-me-form"]')
      .should('be.visible')
      .click();

    // Verify successful submission
    cy.get('[data-testid="calc-accepted-card"]', {
      timeout: TEST_CONSTANTS.TIMEOUTS.DEFAULT,
    }).should('be.visible');

    cy.url().should('include', '/request-received');

    // Verify all interactions were logged
    cy.wait('@formInteraction');
    cy.wait('@questionInteraction');
    cy.get('@formInteraction.all').should('have.length', 1);
    cy.get('@questionInteraction.all').should('have.length', 1);
  });

  afterEach(() => {
    // Reset to initial state
    cy.intercept('GET', `**/web/interests/${calcCreated.id}/`, calcCreated);
  });
});

// Prevent uncaught exceptions from failing tests
Cypress.on('uncaught:exception', (err, runnable) => {
  console.error('Uncaught exception:', err);
  return false;
});
```

