import { FormattedMessage as T } from 'react-intl';
import { Button } from '@otovo/rainbow';
import Modal from '@otovo/shared/components/Modal/ModalPortal';
import { useRouter } from 'next/router';
import { useEffect, useState } from 'react';
import ModalCard from '@otovo/shared/components/Modal/ModalCard';
import { Otovo$Locale } from '@otovo/shared/types/otovoweb';
import createInStoreRedirectUrl from './createPhysicalStoreRedirectUrl';
import m from './messages';

const MILLISECONDS_IN_SECOND = 1000;

type Props = {
  isInterestActivated: boolean;
};

const InactivityDetector = ({ isInterestActivated }: Props) => {
  const router = useRouter();
  const redirectUrl = createInStoreRedirectUrl(router.locale as Otovo$Locale);
  const [lastActivityTime, setLastActivityTime] = useState<number>(Date.now());
  const [inactiveTime, setInactiveTime] = useState<number>(0);
  const [isWarningModalShown, setIsWarningModalShown] =
    useState<boolean>(false);

  let showWarningModalAfter = 30;
  let redirectAfter = isInterestActivated ? 10 : 45;

  if (process.env.NEXT_PUBLIC_SHORT_INACTIVITY_DETECTION) {
    showWarningModalAfter = 1;
    redirectAfter = showWarningModalAfter + 1;
  }

  useEffect(() => {
    const handleActivity = () => {
      setIsWarningModalShown(false);
      setLastActivityTime(Date.now());
    };

    const checkInactivity = () => {
      const currentTime = Date.now();
      const tempInactiveTime = currentTime - lastActivityTime;

      setInactiveTime(Math.round(tempInactiveTime / MILLISECONDS_IN_SECOND));

      if (tempInactiveTime > showWarningModalAfter * MILLISECONDS_IN_SECOND) {
        setIsWarningModalShown(true);
      }
      if (tempInactiveTime > redirectAfter * MILLISECONDS_IN_SECOND) {
        router.push(redirectUrl);
      }
    };

    document.addEventListener('mousemove', handleActivity);
    document.addEventListener('keypress', handleActivity);
    document.addEventListener('touchstart', handleActivity);

    const interval = setInterval(checkInactivity, MILLISECONDS_IN_SECOND);

    return () => {
      document.removeEventListener('mousemove', handleActivity);
      document.removeEventListener('keypress', handleActivity);
      document.removeEventListener('touchstart', handleActivity);
      clearInterval(interval);
    };
  }, [
    router,
    lastActivityTime,
    redirectAfter,
    showWarningModalAfter,
    redirectUrl,
  ]);

  return (
    <Modal show={isWarningModalShown}>
      <ModalCard className="mx-2 overflow-auto sm:mx-auto">
        <div
          data-testid="inactivity-monitor"
          className="p-6 text-sm text-grey-90 md:p-10"
        >
          <h2 className="mb-2 text-lg font-bold">
            <T {...m.stillHereHeader} />
          </h2>
          <p className="text-md">
            <T {...m.stillHereSubtitle} />
          </p>
          <p className="text-md">
            <T
              {...m.stillHereDescription}
              values={{ seconds: Math.max(redirectAfter - inactiveTime, 1) }}
            />
          </p>
          <Button mt="6" fontSize="2" width="100%">
            <T {...m.stillHereButton} />
          </Button>
        </div>
      </ModalCard>
    </Modal>
  );
};

export default InactivityDetector;
